// ---- Pillar 1: Rank Tracker — SerpBear → Supabase ----
// Pulls current keyword positions, detects changes, upserts into keywords table.
// Architecture: single Code node for full async control + error resilience.
const ENV = (typeof $env !== 'undefined' && $env) ? $env : process.env;
const SBKEY = ENV.SERPBEAR_API_KEY;
const SBURL = 'http://localhost:3000'; // internal VPS call, no port exposure needed
const DOMAIN = 'markexis.com';

if (!SBKEY) return [{ json: { error: 'SERPBEAR_API_KEY not set', ok: false } }];

// 1) Fetch current positions from SerpBear
let keywords = [];
try {
  const sb = await this.helpers.httpRequest({
    method: 'GET',
    url: `${SBURL}/api/keywords?domain=${encodeURIComponent(DOMAIN)}`,
    headers: { Authorization: `Bearer ${SBKEY}` },
    json: true, timeout: 20000
  });
  keywords = sb.keywords || [];
} catch (e) {
  return [{ json: { error: `SerpBear fetch failed: ${e.message}`, ok: false } }];
}

if (!keywords.length) return [{ json: { message: 'No keywords tracked yet', ok: true, count: 0 } }];

// 2) Batch upsert to Supabase — one request per keyword to preserve dedup on keyword
//    Use Promise.allSettled so one failure doesn't block the rest
const upserts = keywords.map(kw => {
  const row = {
    keyword: kw.keyword,
    current_position: kw.position || null,
    previous_position: kw.history?.length ? kw.history[kw.history.length - 1] : null,
    volume: kw.volume || null,
    pillar: detectPillar(kw.keyword),
    cluster: detectCluster(kw.keyword),
    last_checked: new Date().toISOString()
  };
  return this.helpers.httpRequest({
    method: 'POST',
    url: `${ENV.SUPABASE_URL}/rest/v1/keywords?on_conflict=keyword`,
    headers: {
      apikey: ENV.SUPABASE_ANON_KEY,
      Authorization: `Bearer ${ENV.SUPABASE_ANON_KEY}`,
      'Content-Type': 'application/json',
      Prefer: 'resolution=merge-duplicates'
    },
    body: JSON.stringify(row),
    json: false, timeout: 15000
  }).then(() => ({ kw: kw.keyword, pos: kw.position, ok: true }))
    .catch(e => ({ kw: kw.keyword, ok: false, err: e.message.slice(0, 100) }));
});

const results = await Promise.allSettled(upserts);
const settled = results.map(r => r.value || r.reason);
const ok = settled.filter(r => r.ok).length;
const failed = settled.filter(r => !r.ok).length;

// 3) Detect significant drops (position worsened by 5+) for alerting
const drops = settled.filter(r => r.ok && r.prevPos && r.pos && (r.pos - r.prevPos) >= 5);

return [{ json: { ok: true, total: keywords.length, upserted: ok, failed, drops: drops.length, domain: DOMAIN, checkedAt: new Date().toISOString() } }];

function detectPillar(kw) {
  const k = kw.toLowerCase();
  if (k.includes('latam') || k.includes('latin america') || k.includes('mexico') || k.includes('brazil')) return 'latam';
  if (k.includes('ai ') || k.includes('artificial intelligence')) return 'ai';
  return 'gtm';
}
function detectCluster(kw) {
  const k = kw.toLowerCase();
  if (k.includes('latam') || k.includes('latin america') || k.includes('mexico') || k.includes('brazil')) return 'cluster_1_latam';
  if (k.includes('ai ') || k.includes('artificial intelligence')) return 'cluster_2_ai';
  if (k.includes('consult') || k.includes('agency')) return 'cluster_4_competitor';
  return 'cluster_3_gtm';
}
